import{c as e,Q as a,j as r,m as o}from"./chunks/framework.DpF7k2f3.js";const m=JSON.parse('{"title":"제6장 RAG 검색 증강 생성","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ko/part2-fundamentals/chapter6.md","filePath":"ko/part2-fundamentals/chapter6.md"}'),n={name:"ko/part2-fundamentals/chapter6.md"};function p(l,t,i,s,d,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="제6장-rag-검색-증강-생성" tabindex="-1">제6장 RAG 검색 증강 생성 <a class="header-anchor" href="#제6장-rag-검색-증강-생성" aria-label="Permalink to &quot;제6장 RAG 검색 증강 생성&quot;">​</a></h1><p>##本章에서 배울 것들</p><p>제5장이 &quot;怎么让大模型听你的话&quot;를 가르쳤다면, 이 챕터는 &quot;怎么让大模型知道它原本不知道的事&quot;를 가르칩니다.</p><p>RAG(Retrieval-Augmented Generation, 검색 증강 생성)은 AI 앱 개발에서 가장 핵심적인 기술 중 하나입니다. 면접에서 80% RAG에 대해 물어보고, 프로젝트를 할 때 열 개 중 아홉 개에서 RAG가 필요합니다. 이유는 간단합니다: 모델이 아무리 강해도 지식 경계가 있습니다 - 회사 내부 문서, 업무 프로세스, 최신 제품 데이터를 모릅니다. RAG는 바로 이것을 해결하기 위한 것입니다.</p><p>하지만 많은 학생들은 RAG의 표면만 배웠습니다 - 벡터 검색을 알고, 문서를 막 자르고, 파라미터를 막 조정하면 OK라고 생각합니다. 면접관이 조금만 깊이 물어보면 바로露馅: 리랭킹怎么处理? 이 시나리오에서 왜语义切块而非递归切块? Self-RAG와 CRAG의 차이는? 멀티모달 문서怎么处理?</p><p>이 챕터를 읽고 나면 가져갈 것들:</p><ul><li>RAG의 본질에 대한 깊은 이해: &quot;검색+생성&quot;이 아니라 지식 경계 문제를 해결하는 체계적 엔지니어링</li><li>텍스트 청킹의 N가지 전략 마스터: 재귀적, 시맨틱, Parent-Child, 언제 무엇을 사용해야 하는지</li><li>Embedding 모델 선택: 2026년 중국어 Embedding哪家强,怎么微调,什么时候需要微调</li><li>검색 전략 마스터: 하이브리드 검색, 리랭킹, 쿼리 재작성, 적응형 검색</li></ul><hr><blockquote><p><strong>전체 번역은 곧 제공될 예정입니다. 지금은中文版을 읽으실 수 있습니다.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter6.html">中文版阅读</a></p></blockquote>',9)])])}const _=e(n,[["render",p]]);export{m as __pageData,_ as default};
